26	    const staticBitmasks = query.staticBitmasks;
27	    const trackingGroups = query.trackingGroups;
28	    const generations = query.generations;
29	    const traitInstancesAll = query.traitInstances.all;
30	    const entityMasks = world[$internal].entityMasks;
31	    const eid = getEntityId(entity);
32	
33	    const generationsLen = generations.length;
34	    const trackingGroupsLen = trackingGroups.length;
35	
36	    // Early exit: no traits to check
37	    if (traitInstancesAll.length === 0) return false;
