39	    // 1. Check static constraints (required/forbidden/or)
40	    for (let i = 0; i < generationsLen; i++) {
41	        const generationId = generations[i];
42	        const bitmask = staticBitmasks[i];
43	        if (!bitmask) continue;
44	
45	        const required = bitmask.required;
46	        const forbidden = bitmask.forbidden;
47	        const or = bitmask.or;
48	
49	        // PERF: Direct access + bitwise OR coerces undefined to 0
50	        const genMasks = entityMasks[generationId];
51	        const entityMask = genMasks ? (genMasks[eid] | 0) : 0;
52	
53	        // Check forbidden traits
54	        if (forbidden && (entityMask & forbidden) !== 0) return false;
55	
56	        // Check required traits
57	        if (required && (entityMask & required) !== required) return false;
58	
59	        // Check Or traits
60	        if (or !== 0 && (entityMask & or) === 0) return false;
