70	        const groupType = group.type;
71	        const groupLogic = group.logic;
72	        const groupBitmasks = group.bitmasks;
73	        const groupBitmask = groupBitmasks[eventGenerationId];
74	
75	        // Check if this event affects this group's traits
76	        if (groupBitmask && (groupBitmask & eventBitflag)) {
