78	            // - Remove event invalidates Added/Changed tracking
79	            // - Add event invalidates Removed/Changed tracking
80	            if (eventType === 'remove') {
81	                if (groupType === 'add' || groupType === 'change') return false;
82	            } else if (eventType === 'add') {
83	                if (groupType === 'remove' || groupType === 'change') return false;
84	            }
85	
