import type { Entity } from '../entity/types';
import { addTrait, getTrait, hasTrait, removeTrait, setTrait, trait } from '../trait/trait';
import type { ConfigurableTrait, Trait } from '../trait/types';
import type { World } from '../world';
import { $aspectRef } from './symbols';
import type { Aspect, AspectRecord, AspectValue } from './types';

let aspectId = 0;

/**
 * Flatten traits and nested aspects into a single list of traits.
 */
function flattenConstituents(constituents: (Trait | Aspect)[]): Trait[] {
    const traits: Trait[] = [];
    for (const constituent of constituents) {
        if (isAspect(constituent)) traits.push(...constituent.traits);
        else traits.push(constituent);
    }
    return traits;
}

export function createAspect<T extends (Trait | Aspect)[]>(
    ...constituents: T
): Aspect<FlattenAspectTraits<T>> {
    const traits = flattenConstituents(constituents);

    if (traits.length < 2) {
        throw new Error('Koota: createAspect requires at least two constituent traits.');
    }

    const fieldOwners = new Map<string, Trait>();
    const schema: Record<string, unknown> = {};

    for (const constituentTrait of traits) {
        const traitCtx = constituentTrait[$internal];

        if (traitCtx.relation) {
            throw new Error('Koota: Aspects cannot include relation traits.');
        }

        for (const field of Object.keys(constituentTrait.schema)) {
            const owner = fieldOwners.get(field);
            if (owner) {
                throw new Error(
                    `Koota: Aspect field "${field}" is defined by multiple constituent traits.`
                );
            }
            fieldOwners.set(field, constituentTrait);
            schema[field] = constituentTrait.schema[field as keyof typeof constituentTrait.schema];
        }
    }

    const aspect = {
        [$aspectRef]: true,
        id: aspectId++,
        traits: Object.freeze(traits) as FlattenAspectTraits<T>,
        schema: Object.freeze(schema),
        [$internal]: {
            completeTag: null,
        },
    } as Aspect<FlattenAspectTraits<T>>;

    return Object.freeze(aspect);
}

type FlattenAspectTraits<T extends (Trait | Aspect)[]> = T extends [infer First, ...infer Rest]
    ? Rest extends (Trait | Aspect)[]
        ? [
              ...(First extends Aspect<infer U> ? U : First extends Trait ? [First] : []),
              ...FlattenAspectTraits<Rest>,
          ]
        : First extends Aspect<infer U>
          ? U
          : First extends Trait
            ? [First]
            : []
    : [];

export /* @inline @pure */ function isAspect(value: unknown): value is Aspect {
    return !!(value as any)?.[$aspectRef];
}

/**
 * Get (creating if needed) the tag trait that mirrors an aspect's completeness.
 * Used internally to piggyback aspect transitions onto the existing tracking engine.
 */
export function getAspectCompleteTag(aspect: Aspect): Trait {
    const internal = aspect[$internal];
    if (!internal.completeTag) internal.completeTag = trait();
    return internal.completeTag;
}

const wiredWorlds = new WeakMap<Aspect, Set<number>>();

/**
 * Ensure the aspect's completeness tag stays in sync with its constituents for this world.
 * Idempotent per (aspect, world) pair.
 */
export function ensureAspectWiring(world: World, aspect: Aspect) {
    let wired = wiredWorlds.get(aspect);
    if (!wired) {
        wired = new Set();
        wiredWorlds.set(aspect, wired);
    }
    if (wired.has(world.id)) return;
    wired.add(world.id);

    const completeTag = getAspectCompleteTag(aspect);

    const sync = (entity: Entity) => {
        const isComplete = hasAspect(world, entity, aspect);
        const isMarked = hasTrait(world, entity, completeTag);
        if (isComplete && !isMarked) addTrait(world, entity, completeTag);
        else if (!isComplete && isMarked) removeTrait(world, entity, completeTag);
    };

    for (const constituentTrait of aspect.traits) {
        world.onAdd(constituentTrait, sync);
        world.onRemove(constituentTrait, sync);
    }

    // Sync entities that already satisfy the aspect before wiring was set up.
    for (const entity of world.entities) sync(entity);
}

export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
    const { traits } = aspect;
    for (let i = 0; i < traits.length; i++) {
        if (!hasTrait(world, entity, traits[i])) return false;
    }
    return true;
}

export function getAspect<T extends Trait[]>(
    world: World,
