                sourceAspects.push(input);
                // Matches the transition to all-present.
                return getAspectCompleteTag(input);
            }
            return isRelation(input) ? input[$internal].trait : input;
        });

        const modifier = createModifier(`added-${id}`, id, traits);
        if (sourceAspects.length > 0) modifier.sourceAspects = sourceAspects;

        return modifier;
    };
}
